```

**2. JavaScript (Client-Side - React, Vue, Angular, or Vanilla JS)**

Here's how you'd handle this in different JavaScript environments:

* **React:**

```javascript
import React, { useState, useEffect } from 'react';

function OrderApproval({ order }) {
  const [isApproveButtonEnabled, setIsApproveButtonEnabled] = useState(false);

  useEffect(() => {
    // Check order status and user permissions
    const hasApproverPermission = checkUserPermission('approver'); // Replace with your permission check function
    setIsApproveButtonEnabled(order.status === 'pending' && hasApproverPermission);
  }, [order.status]); // Re-run effect when order status changes

  return (
    <div>
      {isApproveButtonEnabled && (
        <button onClick={() => handleApprove(order.id)}>Approve</button>
      )}
    </div>
  );
}

function checkUserPermission(permissionType) {
  // Replace this with your actual permission checking logic
  // This is just an example.  You'll likely fetch from an API or database.
  const user = { role: 'admin' }; // Example user object
  return user.role === permissionType;
}

function handleApprove(orderId) {
  // Logic to approve the order (e.g., send an API request)
  console.log(`Approving order with ID: ${orderId}`);
}

export default OrderApproval;
```

