                const response = await fetch(`/order/${orderId}`);
                const order = await response.json();
                document.getElementById('orderDetails').innerHTML = `
                    <p>Status: ${order.status}</p>
                    <p>Approver: ${order.approverId}</p>
                `;

                // Check if the order status is 'pending' and the current user has approver permissions
                const userRole = 'approver'; // Replace with actual user role check
                if (order.status === 'pending' && userRole === 'approver') {
                    document.getElementById('approveButton').style.display = 'block';
                } else {
                    document.getElementById('approveButton').style.display = 'none';
                }
            } catch (error) {
                console.error('Error fetching order details:', error);
            }
        }

        // Example usage: Fetch order details for order ID 1
        fetchOrderDetails(1);

        // Approve button
        document.getElementById('approveButton').addEventListener('click', () => {
            alert('Order approved!');
            // Add your approval logic here
        });
    </script>

    <button id="approveButton" style="display: none;">Approve</button>
</body>
</html>
```

### Explanation

1. **Backend**:
   - The server serves order details based on the order ID.
   - It checks if the user has approver permissions before returning the order details.

2. **Frontend**:
   - The HTML contains a button that is initially hidden (`display: none`).
   - JavaScript fetches the order details from the server.
   - Based on the order status and user permissions, it decides whether to show the "Approve" button.

This approach ensures that the "Approve" button is only visible to users who have the necessary permissions and whose associated orders are in the 'pending' state.

