#### Backend (Node.js + Express)

```javascript
const express = require('express');
const app = express();
const port = 3000;

app.use(express.json());

// Mock user data and groups
const users = [
    { id: 1, username: 'user1', groups: ['analytics'] },
    { id: 2, username: 'user2', groups: [] },
];

app.get('/api/user/groups', (req, res) => {
    const userId = req.query.id; // Assuming you pass the user ID as a query parameter
    const user = users.find(user => user.id === parseInt(userId));
    if (!user) {
        return res.status(404).send({ error: 'User not found' });
    }
    res.send({ groups: user.groups });
});

app.listen(port, () => {
    console.log(`Server running at http://localhost:${port}`);
});
```

#### Frontend (React)

```jsx
import React from 'react';
import axios from 'axios';

function Dashboard() {
    const [isAnalyticsUser, setIsAnalyticsUser] = React.useState(false);

    React.useEffect(() => {
        const fetchGroups = async () => {
            try {
                const response = await axios.get('/api/user/groups', {
                    params: { id: 1 }, // Replace with actual user ID
                });
                setIsAnalyticsUser(response.data.groups.includes('analytics'));
            } catch (error) {
                console.error('Error fetching user groups:', error);
            }
        };

        fetchGroups();
    }, []);

    return (
        <nav>
            <ul>
                {isAnalyticsUser && (
                    <li>
                        <a href="/export">Export</a>
                    </li>
                )}
                {/* Other navigation items */}
            </ul>
        </nav>
    );
}

export default Dashboard;
